import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { first } from 'rxjs/operators';
import { Account } from '@app/_models';
import { AccountService, AlertService } from '@app/_services';
import { AlertComponent } from '@app/_components/alert.component';

@Component({
  templateUrl: 'list.component.html',
  standalone: true,
  imports: [CommonModule, RouterLink, AlertComponent]
})
export class ListComponent implements OnInit {
  accounts: Account[] = [];
  loading = true;
  error: string | null = null;

  constructor(private accountService: AccountService, private alertService: AlertService) { }

  ngOnInit() {
    this.loadAccounts();
  }

  loadAccounts() {
    this.loading = true;
    this.error = null;
    
    console.log('Loading accounts...');
    
    this.accountService.getAll()
      .pipe(first())
      .subscribe({
        next: (accounts) => {
          console.log('Accounts loaded successfully:', accounts);
          this.accounts = accounts;
          this.loading = false;
        },
        error: (error) => {
          console.error('Error loading accounts:', error);
          this.error = error.error?.message || 'Failed to load accounts. Please try again.';
          this.loading = false;
          this.alertService.error(this.error);
        }
      });
  }

  deleteAccount(account: Account) {
    if (!confirm(`Are you sure you want to delete ${account.firstName} ${account.lastName}?`)) {
      return;
    }
    
    account.isDeleting = true;
    this.accountService.delete(account.id)
      .pipe(first())
      .subscribe({
        next: () => {
          console.log('Account deleted:', account.id);
          this.accounts = this.accounts.filter(x => x.id !== account.id);
          this.alertService.success('Account deleted successfully');
        },
        error: (error) => {
          console.error('Error deleting account:', error);
          account.isDeleting = false;
          this.alertService.error(error.error?.message || 'Failed to delete account');
        }
      });
  }
}
